module rising_edge_detector(  
    input clk,  
    input signal_in,  
    output reg signal_out  
);  
    reg signal_in_q; // Delayed version of the input signal  

    always @(posedge clk) begin  
        signal_in_q <= signal_in;  
        signal_out <= (signal_in && !signal_in_q);  
    end  
endmodule
